// ============================================================
// FLOWSTATE — Trend Scout
// Daily 9am: research trends → match inventory → WhatsApp nudge
// → user replies Y1/Y2/Y3 and existing approval_handler posts it
// ============================================================
const fs     = require('fs');
const path   = require('path');
const crypto = require('crypto');

// ── Config ──────────────────────────────────────────────────────
const OPENAI_KEY   = process.env.OPENAI_API_KEY       || $env.OPENAI_API_KEY;
const TWILIO_SID   = process.env.TWILIO_ACCOUNT_SID   || $env.TWILIO_ACCOUNT_SID;
const TWILIO_TOKEN = process.env.TWILIO_AUTH_TOKEN    || $env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM  = process.env.TWILIO_WHATSAPP_FROM || $env.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886';
const TWILIO_TO    = process.env.TWILIO_WHATSAPP_TO   || $env.TWILIO_WHATSAPP_TO;
const SCRIPTS_DIR  = process.env.SCRIPTS_DIR || 'D:\\your-content-folder\\scripts';

// CONFIGURE THIS: Describe your content niches for better trend research.
// Example: 'lifestyle, fashion, fitness, home decor, food, travel'
const PERSONA_NICHES = process.env.PERSONA_NICHES || 'lifestyle, fashion, fitness';

const PENDING_PATH   = path.join(SCRIPTS_DIR, 'pending_approvals.json');
const INVENTORY_PATH = path.join(SCRIPTS_DIR, 'content_inventory.json');

// ── Helpers ────────────────────────────────────────────────────
async function callOpenAI(messages, jsonMode = false) {
  const body = {
    model: 'gpt-4o',
    messages,
  };
  if (jsonMode) body.response_format = { type: 'json_object' };

  const resp = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + OPENAI_KEY,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });
  const data = await resp.json();
  return data.choices?.[0]?.message?.content || '';
}

async function sendWhatsApp(msg) {
  const url    = `https://api.twilio.com/2010-04-01/Accounts/${TWILIO_SID}/Messages.json`;
  const creds  = Buffer.from(`${TWILIO_SID}:${TWILIO_TOKEN}`).toString('base64');
  await fetch(url, {
    method:  'POST',
    headers: { 'Authorization': 'Basic ' + creds, 'Content-Type': 'application/x-www-form-urlencoded' },
    body:    new URLSearchParams({ From: TWILIO_FROM, To: TWILIO_TO, Body: msg }).toString(),
  });
}

// ── Step 1: Load inventory ─────────────────────────────────────
let inventory = [];
try {
  inventory = JSON.parse(fs.readFileSync(INVENTORY_PATH, 'utf8'));
} catch(e) {
  await sendWhatsApp('⚠️ Trend Scout: no content_inventory.json found. Run content_db_updater.py first.');
  return [{ action: 'no_inventory' }];
}

const candidates = inventory.filter(i =>
  i.IG === true &&
  !i.posted &&
  !i.is_sensitive
);

if (candidates.length === 0) {
  await sendWhatsApp('📅 No new IG-eligible content in your library. Drop some files into your content folder.');
  return [{ action: 'no_candidates' }];
}

// ── Step 2: Research trends ──────────────────────────────────
const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
const trendRaw = await callOpenAI([
  {
    role: 'system',
    content: 'You are a social media trend analyst. Return JSON only, no other text.'
  },
  {
    role: 'user',
    content: `Today is ${today}. What are trending hashtags and content themes for creators in: ${PERSONA_NICHES}. Platforms: Instagram and Threads. Return JSON with: {"hashtags": ["#tag1", ...10 tags], "themes": ["theme 1", ...5 themes], "post_concept": "one sentence trending post idea", "best_time_to_post": "e.g. 7-9pm EST"}`
  }
], true);

let trends = { hashtags: [], themes: [], post_concept: '', best_time_to_post: '' };
try {
  trends = JSON.parse(trendRaw);
} catch(e) {
  console.log('[TrendScout] Could not parse trends:', e.message);
}

// ── Step 3: Score inventory against trends ──────────────────────
const trendKeywords = [...trends.hashtags, ...trends.themes]
  .map(t => t.toLowerCase().replace(/[#_]/g, ' ').trim())
  .flatMap(t => t.split(/\s+/));

function score(item) {
  const text = [item.vibe, item.activity, item.style, item.folder_label]
    .filter(Boolean).join(' ').toLowerCase();
  return trendKeywords.filter(kw => kw.length > 3 && text.includes(kw)).length;
}

const ranked = candidates
  .map(i => ({ ...i, _score: score(i) }))
  .sort((a, b) => b._score - a._score);

const pick = ranked[0];

// ── Step 4: Generate 3 trend-aware captions ─────────────────────
const trendLine   = trends.hashtags.slice(0, 5).join(' ');
const captionRaw  = await callOpenAI([
  {
    role: 'system',
    // CONFIGURE THIS: Replace with your persona's voice brief.
    content: 'You write short Instagram captions in the creator\'s authentic voice. No hashtags in the caption body. Under 150 characters each. Return JSON only.'
  },
  {
    role: 'user',
    content: `Trending today: ${trendLine}\n\nContent: ${pick.folder_label || 'lifestyle'} folder. Vibe: ${pick.vibe || ''}. Activity: ${pick.activity || ''}. Style: ${pick.style || ''}.\n\nWrite 3 caption options that subtly tap into these trends without forcing it. Return: {"c1": "...", "c2": "...", "c3": "..."}`
  }
], true);

let caps = { c1: 'new drop.', c2: 'something quiet.', c3: 'just this.' };
try {
  caps = JSON.parse(captionRaw);
} catch(e) {
  console.log('[TrendScout] Could not parse captions:', e.message);
}

// ── Step 5: Save to pending_approvals.json ─────────────────────
let pending = {};
try {
  pending = JSON.parse(fs.readFileSync(PENDING_PATH, 'utf8'));
} catch(e) { pending = {}; }

// Skip if this file is already queued
const alreadyQueued = Object.values(pending).some(
  i => i.fileName === pick.filename && i.status === 'pending'
);

if (!alreadyQueued) {
  const approvalId = crypto.randomUUID();
  pending[approvalId] = {
    id:            approvalId,
    fileName:      pick.filename,
    instagramPath: pick.full_path,
    captions:      [caps.c1, caps.c2, caps.c3],
    hashtags:      trends.hashtags.slice(0, 7),
    status:        'pending',
    createdAt:     new Date().toISOString(),
    source:        'trend_scout',
    trendContext:  trends.hashtags.slice(0, 5).join(' '),
  };
  fs.writeFileSync(PENDING_PATH, JSON.stringify(pending, null, 2));
  console.log('[TrendScout] Saved to pending:', pick.filename);
}

// ── Step 6: Send WhatsApp nudge ────────────────────────────────
const hashtagLine  = trends.hashtags.slice(0, 5).join(' ');
const conceptLine  = trends.post_concept ? `\nTrending concept: ${trends.post_concept}` : '';
const timeLine     = trends.best_time_to_post ? `\nBest time to post: ${trends.best_time_to_post}` : '';
const reelSuggestion = trends.post_concept
  ? `\n\nOr send: IDEA: ${trends.post_concept.toLowerCase()}, 20s VO`
  : '';

const msg = [
  `📈 Trending today: ${hashtagLine}${conceptLine}${timeLine}`,
  ``,
  `Best match: ${pick.folder_label}/${pick.filename}`,
  ``,
  `Y1: "${caps.c1}"`,
  `Y2: "${caps.c2}"`,
  `Y3: "${caps.c3}"`,
  ``,
  `Reply Y1/Y2/Y3 to post. N to skip.${reelSuggestion}`,
].join('\n');

await sendWhatsApp(msg);
console.log('[TrendScout] Done. Pick:', pick.filename, '| Trend score:', pick._score);

return [{
  action:      'sent',
  pick:        pick.filename,
  trendScore:  pick._score,
  hashtags:    trends.hashtags.slice(0, 5),
  captionSent: caps.c1,
}];
